import { ProjectsClient } from "@azure/ai-projects";
import { VexClient } from "vex-sdk";

const client = new ProjectsClient("https://your-project.api.azure.com", credential);
const vex = new VexClient("vex-api-key");

export async function handleAgentMessage(threadId: string, content: string) {
  const thread = await client.getThread(threadId);

  const response = await client.createMessage({
    agentId: "voice-agent",
    threadId,
    content
  });

  // Vex validates tool calls and grounding
  const verified = await vex.verify({
    agentResponse: response,
    checks: ["tool_policy", "data_freshness", "latency_budget"],
    enterprisePolicy: "your-dlp-policy"
  });

  if (verified.passed) {
    return verified.content;
  }

  // Graceful degradation
  return "I need to check that information. Let me get back to you.";
}

import { VexClient } from "vex-sdk";

const vex = new VexClient("vex-key");

interface ConversationState {
  threadId: string;
  last3turns: string[];
  topic: string;
}

export async function ensureCoherence(state: ConversationState, newResponse: string) {
  const check = await vex.verify({
    type: "conversation_coherence",
    context: {
      history: state.last3turns,
      currentTopic: state.topic,
      proposedResponse: newResponse
    },
    thresholds: {
      topic_drift: 0.2,
      repetition: 0.1
    }
  });

  if (!check.passed) {
    return await vex.generate_repair(
      issue=check.failure_reason,
      context=state
    );
  }

  state.last3turns.push(newResponse);
  return newResponse;
}

